{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires a two-stage approach: first, an optimal search strategy to locate the polyominoes using noisy queries, and second, a reconstruction algorithm to map the exact cell coordinates.",
  "helpers": [
    {
      "label": "search_strategy_optimizer",
      "instructions": "Develop a decision-making algorithm for selecting drilling coordinates and aggregate query locations that minimizes the expected number of probes. The algorithm must account for the noisy nature of the aggregate queries and the known shapes of the polyominoes to maximize information gain per probe, specifically using a Bayesian update or entropy-reduction approach to narrow down the possible placement configurations."
    },
    {
      "label": "polyomino_reconstruction_engine",
      "instructions": "Given a set of noisy aggregate query results and a list of possible polyomino shapes, implement a constraint satisfaction or maximum likelihood estimation procedure to identify the exact cell coordinates of all oil-containing cells. The logic must resolve overlaps and shape orientations to find the most probable spatial configuration that matches the observed query data."
    }
  ],
  "synthesis_brief": "Combine the optimized probing sequence from the first helper to gather data, then feed the resulting query outcomes into the reconstruction engine to produce the final set of oil-containing cell coordinates."
}
```

